def trimmed_mean(nums):
    if not nums or len(nums) < 3:
        return None

    nums.sort()
    min_idx = max(0, len(nums)-3)
    max_idx = min(len(nums)-1, len(nums)-min_idx)
    sum_of_middle = sum(nums[min_idx:max_idx+1])
    return sum_of_middle / (max_idx - min_idx + 1)
